const part1 = $input.item.json['1 часть статьи'] ?? '';
const part2 = $input.item.json['2 часть статьи'] ?? '';

const rawText = [part1, part2].filter(Boolean).join('\n\n');

function cleanHtmlToText(html) {
  if (typeof html !== 'string') return '';

  return html
    // <a ...>текст</a> -> "текст"
    .replace(/<a\b[^>]*>([\s\S]*?)<\/a>/gi, '$1')

    // удалить любые URL
    .replace(/https?:\/\/[^\s"'<>]+/gi, '')

    // блочные теги -> переносы
    .replace(/<\/h[1-6]>/gi, '\n\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/ul>/gi, '\n\n')
    .replace(/<br\s*\/?>/gi, '\n')

    // удалить остальные теги
    .replace(/<[^>]+>/g, '')

    // HTML-сущности
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')

    // пробелы/переносы
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const cleanText = cleanHtmlToText(rawText);

return {
  json: {
    ...$input.item.json,
    cleanText,
  },
};

