// Получаем текст из output (структура AI Agent)
const text = $input.first().json.output.content;

// Очищаем от Markdown
const clean = text
  .replace(/#{1,6}\s*/g, '')       // Удаляем # и ###
  .replace(/\*/g, '')              // Удаляем *
  .replace(/\[[^\]]+\]/g, '')      // Удаляем [текст]
  .trim();

// Возвращаем в правильной структуре
return [{
  json: {
    output: clean  // ← ВАЖНО: возвращаем в output, не в message.content
  }
}];

// Получаем текст из output (структура AI Agent)
const text = items[0].json.output;

// Очищаем от Markdown
const clean = text
  .replace(/#{1,6}\s*/g, '')       // Удаляем # и ###
  .replace(/\*/g, '')              // Удаляем *
  .replace(/\[[^\]]+\]/g, '')      // Удаляем [текст]
  .trim();

// Разбиваем на части по 3000 символов
const MAX_LENGTH = 3000;

if (clean.length <= MAX_LENGTH) {
  return [{
    json: {
      output: clean,
      part: 1,
      totalParts: 1
    }
  }];
}

// Разбиваем текст на части, стараясь резать по абзацам или предложениям
const parts = [];
let remaining = clean;

while (remaining.length > 0) {
  if (remaining.length <= MAX_LENGTH) {
    parts.push(remaining);
    break;
  }

  let cutIndex = MAX_LENGTH;

  // Пробуем найти последний разрыв абзаца (\n\n) в пределах лимита
  const lastParagraph = remaining.lastIndexOf('\n\n', MAX_LENGTH);
  if (lastParagraph > MAX_LENGTH * 0.5) {
    cutIndex = lastParagraph;
  } else {
    // Иначе ищем последний перенос строки
    const lastNewline = remaining.lastIndexOf('\n', MAX_LENGTH);
    if (lastNewline > MAX_LENGTH * 0.5) {
      cutIndex = lastNewline;
    } else {
      // Иначе ищем последнюю точку с пробелом (конец предложения)
      const lastSentence = remaining.lastIndexOf('. ', MAX_LENGTH);
      if (lastSentence > MAX_LENGTH * 0.5) {
        cutIndex = lastSentence + 1; // включаем точку
      }
    }
  }

  parts.push(remaining.substring(0, cutIndex).trim());
  remaining = remaining.substring(cutIndex).trim();
}

// Возвращаем массив сообщений — каждое как отдельный item
return parts.map((part, index) => ({
  json: {
    output: part,
    part: index + 1,
    totalParts: parts.length
  }
}));

// CODE нода: "AI News Viral Filter & Selector"
// Анализирует новости от Perplexity и выбирает самую вирусную

const input = $input.first();

// Проверяем, что данные пришли от Perplexity
if (!input || !input.json || !input.json.choices) {
  throw new Error('❌ Нет данных от Perplexity для обработки');
}

// Извлекаем JSON из ответа Perplexity
let newsData;
try {
  const perplexityResponse = input.json.choices[0].message.content;
  newsData = JSON.parse(perplexityResponse);
} catch (error) {
  throw new Error('❌ Не удалось разобрать JSON от Perplexity: ' + error.message);
}

// Проверяем, что получили массив новостей
if (!Array.isArray(newsData) || newsData.length === 0) {
  throw new Error('❌ Нет новостей для анализа');
}

console.log(`📊 Получено ${newsData.length} новостей для анализа`);

// --- СИСТЕМА ОЦЕНКИ ВИРУСНОСТИ ---
function calculateViralScore(newsItem) {
  let viralScore = 0;
  let reasons = [];

  // 1. ENGAGEMENT SCORE от Perplexity (30%)
  const baseEngagement = newsItem.engagement_score || 5;
  viralScore += (baseEngagement / 10) * 30;
  reasons.push(`Base engagement: ${baseEngagement}/10`);

  // 2. КЛЮЧЕВЫЕ СЛОВА ТРЕНДОВ (25%)
  const trendKeywords = [
    // Горячие компании/продукты
    'openai', 'gpt-5', 'chatgpt', 'claude', 'gemini', 'o1', 'reasoning',
    // Прорывные технологии
    'agi', 'breakthrough', 'world model', 'agents', 'agentic',
    // Большие деньги
    'billion', 'funding', 'valuation', 'ipo', 'acquisition',
    // Драма/конфликты
    'lawsuit', 'fired', 'quit', 'controversy', 'battle',
    // Российская специфика
    'russia', 'yandex', 'sber'
  ];

  const titleLower = (newsItem.title || '').toLowerCase();
  const descLower = (newsItem.description || '').toLowerCase();
  const combinedText = titleLower + ' ' + descLower;

  const keywordMatches = trendKeywords.filter(keyword => 
    combinedText.includes(keyword)
  ).length;

  const keywordScore = Math.min(keywordMatches * 5, 25);
  viralScore += keywordScore;
  reasons.push(`Trend keywords: ${keywordMatches} matches (+${keywordScore})`);

  // 3. ЭМОЦИОНАЛЬНЫЙ КРЮЧОК (20%)
  const emotionalTriggers = [
    // Удивление
    'shocking', 'unexpected', 'surprising', 'incredible', 'amazing',
    // Страх/тревога
    'dangerous', 'threat', 'warning', 'crisis', 'concern',
    // Любопытство
    'secret', 'revealed', 'leaked', 'insider', 'exclusive',
    // FOMO
    'first', 'new', 'latest', 'breaking', 'just announced',
    // Русские эмоциональные слова
    'революция', 'прорыв', 'сенсация', 'скандал'
  ];

  const emotionalMatches = emotionalTriggers.filter(trigger => 
    combinedText.includes(trigger)
  ).length;

  const emotionalScore = Math.min(emotionalMatches * 4, 20);
  viralScore += emotionalScore;
  reasons.push(`Emotional triggers: ${emotionalMatches} matches (+${emotionalScore})`);

  // 4. ИСТОЧНИК И ДОСТОВЕРНОСТЬ (15%)
  const premiumSources = [
    'techcrunch', 'verge', 'wired', 'reuters', 'bloomberg', 
    'fortune', 'wsj', 'nytimes', 'guardian', 'bbc'
  ];

  const sourceLower = (newsItem.source || '').toLowerCase();
  const sourceScore = premiumSources.some(source => 
    sourceLower.includes(source)
  ) ? 15 : 8;

  viralScore += sourceScore;
  reasons.push(`Source quality: ${newsItem.source} (+${sourceScore})`);

  // 5. СВЕЖЕСТЬ НОВОСТИ (10%)
  const newsDate = new Date(newsItem.date);
  const now = new Date();
  const hoursOld = (now - newsDate) / (1000 * 60 * 60);

  let freshnessScore = 10;
  if (hoursOld > 24) freshnessScore = 8;
  if (hoursOld > 48) freshnessScore = 5;
  if (hoursOld > 72) freshnessScore = 2;

  viralScore += freshnessScore;
  reasons.push(`Freshness: ${Math.round(hoursOld)}h old (+${freshnessScore})`);

  return {
    score: Math.round(viralScore),
    reasons: reasons,
    breakdown: {
      engagement: baseEngagement,
      keywords: keywordMatches,
      emotional: emotionalMatches,
      source: newsItem.source,
      hoursOld: Math.round(hoursOld)
    }
  };
}

// Анализируем каждую новость
const analyzedNews = newsData.map((newsItem, index) => {
  const analysis = calculateViralScore(newsItem);

  console.log(`\n📰 Новость ${index + 1}: ${newsItem.title}`);
  console.log(`🔥 Viral Score: ${analysis.score}/100`);
  console.log(`📋 Анализ: ${analysis.reasons.join(', ')}`);

  return {
    ...newsItem,
    viral_analysis: analysis,
    original_index: index + 1
  };
});

// Сортируем по вирусному потенциалу
analyzedNews.sort((a, b) => b.viral_analysis.score - a.viral_analysis.score);

// Выбираем ТОП-1 самую вирусную новость
const topNews = analyzedNews[0];

// Дополнительные метрики для отчетности
const avgScore = analyzedNews.reduce((sum, item) => 
  sum + item.viral_analysis.score, 0) / analyzedNews.length;

const winnerNews = {
  ...topNews,
  // Добавляем обязательные параметры для workflow
  направление: 'Perplexity',
  категория: 'Новость',
  selection_metadata: {
    strategy: 'viral_potential_analysis',
    selected_from_total: newsData.length,
    viral_score: topNews.viral_analysis.score,
    avg_score_all_news: Math.round(avgScore),
    selection_timestamp: new Date().toISOString(),
    winner_reasons: topNews.viral_analysis.reasons,
    original_position: topNews.original_index
  },
  // Статистика для дашборда
  batch_statistics: {
    all_scores: analyzedNews.map(item => item.viral_analysis.score),
    score_range: {
      min: Math.min(...analyzedNews.map(item => item.viral_analysis.score)),
      max: Math.max(...analyzedNews.map(item => item.viral_analysis.score))
    },
    total_news_analyzed: newsData.length,
    selection_confidence: topNews.viral_analysis.score > 70 ? 'high' : 
                         topNews.viral_analysis.score > 50 ? 'medium' : 'low'
  },
  // Флаг для следующих нод
  ready_for_content: true,
  workflow_timestamp: new Date().toISOString()
};

// Финальный лог
console.log(`\n🏆 ПОБЕДИТЕЛЬ: "${topNews.title}"`);
console.log(`🔥 Viral Score: ${topNews.viral_analysis.score}/100`);
console.log(`📊 Средний score всех новостей: ${Math.round(avgScore)}`);
console.log(`🎯 Confidence: ${winnerNews.batch_statistics.selection_confidence}`);

// Возвращаем только одну самую вирусную новость
return [{ json: winnerNews }];

// Фильтрация и дедупликация новостей за последние 13 часов
const items = $input.all();
const CUTOFF_HOURS = 24;
const cutoff = new Date(Date.now() - CUTOFF_HOURS * 60 * 60 * 1000);

const uniqueNews = [];
const seenUrls = new Set();

for (const item of items) {
  const data = item.json;

  // Дата публикации
  const pubDate = new Date(data.pubDate || data.isoDate);
  if (!pubDate || isNaN(pubDate) || pubDate < cutoff) continue;

  // Дедуп по ссылке (можно добавить нормализацию, см. ниже)
  if (!data.link || seenUrls.has(data.link)) continue;
  seenUrls.add(data.link);

  // Берём содержимое из доступных полей
  const rssContent = data['content:encodedSnippet'] || data.content || data.contentSnippet || data.summary || '';

  // Чистим HTML
  const cleanRssContent = String(rssContent)
    .replace(/<[^>]*>/g, '')
    .replace(/&[^;]+;/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  uniqueNews.push({
    title: data.title,
    link: data.link,
    rssContent: cleanRssContent,
    contentSnippet: data.contentSnippet || '',
    pubDate: data.pubDate || data.isoDate,
    source: data['dc:creator'] || data.meta?.title || 'Unknown',
    guid: data.guid
  });
}

console.log(`Filtered ${uniqueNews.length} unique news from ${items.length} total (last ${CUTOFF_HOURS}h)`);

return uniqueNews.map(item => ({ json: item }));

// 1. Получаем все входящие элементы в виде массива
const allItems = $input.all();

// 2. Из каждого элемента забираем только его 'json' часть (саму новость)
// и складываем в новый массив.
const newsArray = allItems.map(item => item.json);

// 3. Возвращаем ОДИН-ЕДИНСТВЕННЫЙ новый элемент.
// У этого элемента будет поле 'data', которое содержит массив всех новостей.
// Имя 'data' важно, так как оно используется в промте: {{$json.data}}
return [{
  json: {
    data: newsArray
  }
}];

// n8n Code node (Run Once For All Items, JavaScript)
// Добавляет ОЧИЩЕННУЮ ссылку в конец текста: "Источник: https://site.com/path…"

const COLS_MODE = false; // false -> много строк { num, text }

function asString(x) {
  if (x == null) return '';
  if (typeof x === 'string') return x;
  try { return JSON.stringify(x); } catch { return String(x); }
}

function extractArray(raw) {
  let s = asString(raw).trim();
  const start = s.indexOf('[');
  const end   = s.lastIndexOf(']');
  if (start !== -1 && end !== -1 && end > start) s = s.slice(start, end + 1);
  s = s.replace(/^```(?:json|javascript)?\s*/i, '').replace(/```$/i, '').trim();
  return JSON.parse(s);
}

function pickUrl(o) {
  let u = o.link ?? o.url ?? o.sourceUrl ?? '';
  if (typeof u !== 'string') u = asString(u);
  u = (u || '').trim();
  if (!u) {
    const inText = asString(o.caption ?? o.text ?? '');
    const m = inText.match(/https?:\/\/\S+/);
    if (m) u = m[0].replace(/[)\]\s]+$/,'');
  }
  return u;
}

// локальное "укорочение": убираем трекинги и делаем короткое отображение
function cleanUrl(u) {
  try {
    const url = new URL(u);
    const DROP = [/^utm_/i, /^fbclid$/i, /^gclid$/i, /^igshid$/i, /^mc_cid$/i, /^mc_eid$/i, /^mkt_tok$/i, /^ref$/i, /^ref_src$/i];
    for (const k of [...url.searchParams.keys()]) {
      if (DROP.some(rx => rx.test(k))) url.searchParams.delete(k);
    }
    url.hash = '';
    const cleaned = url.toString();

    // короткое представление для текста (но кликабельная часть — весь cleaned)
    let display = cleaned.replace(/^https?:\/\//, '').replace(/^www\./, '');
    if (display.length > 80) {
      display = display.slice(0, 60) + '…' + display.slice(-15);
    }
    return { cleaned, display };
  } catch {
    return { cleaned: u, display: u };
  }
}

const input = (items?.[0]?.json?.output ?? items?.[0]?.json);
const arr = extractArray(input);

const news = arr.map((o, i) => {
  const baseText = asString(o.caption ?? o.text ?? '')
    .replace(/\s+/g, ' ')
    .trim();

  const raw = pickUrl(o);
  if (!raw) {
    return { num: i + 1, text: baseText };
  }
  const { cleaned, display } = cleanUrl(raw);
  const tail = `\nИсточник: ${cleaned}`;  // кликабельный — очищенный URL
  // Если хочешь максимально компактное отображение, но оставить кликабельность:
  // const tail = `\nИсточник: ${display.startsWith('http') ? display : 'https://' + display}`;

  return { num: i + 1, text: `${baseText}${tail}` };
});

if (COLS_MODE) {
  const row = {};
  for (const n of news) row[`news_${n.num}`] = n.text;
  return [{ json: row }];
} else {
  return news.map(n => ({ json: n }));
}

const html = $input.item.json.output; // полная статья
const headings = [...html.matchAll(/<h2[^>]*>/gi)];

if (headings.length >= 2) {
  const midIndex = Math.floor(headings.length / 2);
  const splitPos = html.indexOf(headings[midIndex][0], headings[midIndex].index);
  return {
    json: {
      part_1: html.substring(0, splitPos).trim(),
      part_2: html.substring(splitPos).trim()
    }
  };
} else {
  // Если мало заголовков — режем примерно посередине по </p>
  const mid = Math.floor(html.length / 2);
  const closestP = html.indexOf('</p>', mid);
  const splitPos = closestP !== -1 ? closestP + 4 : mid;
  return {
    json: {
      part_1: html.substring(0, splitPos).trim(),
      part_2: html.substring(splitPos).trim()
    }
  };
}

const adaptedText = $('Адаптация Telegraph').item.json.output || '';
const title = $('Финальные данные').item.json.topic;

let content = [];

const blocks = adaptedText.match(/<(h2|h3|h4|p|li|ol)[^>]*>([\s\S]*?)<\/\1>|^(?!<).+$/gm) || [];

for (const block of blocks) {
  const tagMatch = block.match(/^<(h2|h3|h4|p|li|ol)/);
  const text = block.replace(/<[^>]+>/g, '').trim();

  if (!text) continue;

  // Проверяем есть ли ссылка в тексте
  const urlMatch = text.match(/(https?:\/\/[^\s]+)/);

  if (urlMatch) {
    const url = urlMatch[1];
    const before = text.replace(url, '').trim();
    const children = [];
    if (before) children.push(before + ' ');
    children.push({ tag: 'a', attrs: { href: url }, children: [url] });
    content.push({ tag: 'p', children: children });
    continue;
  }

  if (!tagMatch) {
    content.push({ tag: 'p', children: [text] });
  } else {
    const tag = tagMatch[1];
    if (tag === 'h2') {
      content.push({ tag: 'h3', children: [text] });
    } else if (tag === 'h3' || tag === 'h4') {
      content.push({ tag: 'h4', children: [text] });
    } else if (tag === 'li') {
      content.push({ tag: 'p', children: ['• ' + text] });
    } else {
      content.push({ tag: 'p', children: [text] });
    }
  }
}

return [{
  json: {
    title: title,
    content: JSON.stringify(content)
  }
}];

const prompt = $('Промпт для картинки, название картинки').item.json.output.image_prompt || "";

const cleanPrompt = prompt.replace(/"/g, "'").replace(/\\/g, "").replace(/[\n\r]/g, " ").trim();

if (!cleanPrompt) {
  throw new Error("Image prompt is empty");
}

return [{
  json: {
    body: {
      prompt: cleanPrompt,
      size: "3:2",
      isEnhance: false,
      uploadCn: false,
      enableFallback: true,
      fallbackModel: "FLUX_MAX"
    }
  }
}];

// Code Node: Split Thread Chains → 3 separate items
// Place AFTER the Threads-Telegram agent node
