  .split('===CHAIN===')
  .map(c => c.trim())
  .filter(c => c.length > 0);

const results = [];

for (let i = 0; i < chains.length; i++) {
  results.push({
    json: {
      threads_text: chains[i],
      chain_number: i + 1,
      source_type: 'article_to_telegram',
      status: 'ready'
    }
