const faqPairs = $('Переменные').first().json.faq_pairs || '';
const part1 = $json['1 часть статьи'] || '';
const part2 = $json['2 часть статьи'] || '';
const midInsert = $json.MID_INSERT || '';
const endInsert = $json.END_INSERT || '';

const pairs = faqPairs.split(' | ').map(pair => {
  const qMatch = pair.match(/Q:\s*(.+?)\s*A:\s*(.+)/);
  if (!qMatch) return null;
  return { question: qMatch[1].trim(), answer: qMatch[2].trim() };
}).filter(Boolean);

let faqSchema = '';
if (pairs.length > 0) {
  const schema = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": pairs.map(p => ({
      "@type": "Question",
      "name": p.question,
      "acceptedAnswer": { "@type": "Answer", "text": p.answer }
    }))
  };
  faqSchema = '<script type="application/ld+json">' + JSON.stringify(schema) + '</script>';
}

let fullArticle = part1 + '\n\n' + part2;
fullArticle = fullArticle.replace('<!--MID_INSERT-->', midInsert);
fullArticle = fullArticle.replace('<!--END_INSERT-->', endInsert);
fullArticle = fullArticle + '\n\n' + faqSchema;

const output = Object.assign({}, $json, {
  faq_schema: faqSchema,
  final_content: fullArticle
});

return [{
  json: output,
  binary: $input.first().binary
}];

const content = $input.first().json.final_content;
const baseUrl = 'https://switchonai.ru';

const placeholders = [...content.matchAll(/\[INTERNAL_LINK: topic="([^"]+)" anchor="([^"]+)"\]/g)];

let resolved = content;

for (const match of placeholders) {
  const [full, topic, anchor] = match;
  resolved = resolved.replace(full, `<a href="${baseUrl}/?s=${encodeURIComponent(topic)}">${anchor}</a>`);
}

return [{ json: { ...($input.first().json), final_content: resolved }, binary: $input.first().binary }];
